import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.hasItem
import org.junit.Test
import org.junit.runner.RunWith
import org.robolectric.Robolectric

@RunWith(AndroidJUnit4::class)
class BackupSettingsSearchBarTest : RobolectricTest() {

    @Test
    @Suppress("UNCHECKED_CAST")
    fun `Backup limits preferences should be indexed`() {
        val preferencesActivity = Robolectric.buildActivity(Preferences::class.java)
            .create().start().resume().get()
        val searchConfig = SearchConfiguration(preferencesActivity)
        HeaderFragment.configureSearchBar(preferencesActivity, searchConfig)

        // Use reflection to access private fields
        val filesToIndexField = getJavaFieldAsAccessible(SearchConfiguration::class.java, "filesToIndex")
        // SearchConfiguration.SearchIndexItem is a private static inner class, so we need to get it via Class.forName or similar if it's not directly accessible
        // However, looking at SettingsSearchBarTest, it seems they access it directly. 
        // If it fails, I'll check how to access it.
        // Wait, SettingsSearchBarTest uses `SearchConfiguration.SearchIndexItem::class.java`. 
        // If it is private, kotlin might not let me reference it like that unless I suppress visibility or it is actually public.
        // Assuming the existing test works, I can do the same.

        val searchItemResIdField = getJavaFieldAsAccessible(SearchConfiguration.SearchIndexItem::class.java, "resId")

        // Get the resIds of the files indexed with `SearchConfiguration.index`
        val filesToIndex = filesToIndexField.get(searchConfig) as ArrayList<*>
        val filesResIds = filesToIndex.map {
            searchItemResIdField.get(it) as Int
        }

        assertThat(
            "Backup limits preferences should be indexed",
            filesResIds,
            hasItem(R.xml.preferences_backup_limits)
        )
    }
}
